module top_module(
	input clk,
	input enable,
	input reset,
	input [11:0] reset_value,
	output reg [11:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (reset)
		q <= reset_value;
	else if (enable)
		q <= q + 1;
end
endmodule
